const sourceNameMap = {
  returns: "Data Warehouse",
  crm: "CRM / Customer Service Platform",
  reviews: "VoC / Review Analytics Engine",
  fraud: "Fraud & Abuse Risk Engine",
  nps: "Post Return NPS",
};

const sourceNamespaceMap = {
  returns: "RAG1",
  crm: "RAG2",
  reviews: "RAG3",
  fraud: "RAG4",
  nps: "RAG5",
};

const sourceOrder = ["returns", "crm", "reviews", "fraud", "nps"];

function formatDisplayTime(value) {
  if (!value) return null;
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleString("en-IN", {
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });
}

function normalizeStatus(value) {
  return String(value || "").toLowerCase() === "synced" ? "Synced" : "Not synced";
}

function normalizeRagStatus(value) {
  return String(value || "").toLowerCase() === "ready" ? "Indexed" : "Not indexed";
}

const rawSources = items.map(item => item.json || {});

const normalizedById = {};
for (const src of rawSources) {
  const id = src.id || src.category;
  if (!id) continue;

  const ragCount = Number(src.ragCount ?? src.ragIndexed ?? 0) || 0;
  const recordsPulled = Number(src.recordsPulled ?? src.rowCount ?? 0) || 0;
  const lastSyncRaw = src.lastSyncTime || src.lastGlobalSyncTime || new Date().toISOString();

  normalizedById[id] = {
    id,
    name: sourceNameMap[id] || src.name || id,
    internalName: src.name || null,
    status: normalizeStatus(src.status),
    lastSyncTime: formatDisplayTime(lastSyncRaw),
    lastSyncTimeRaw: lastSyncRaw,
    recordsPulled,
    recordsUnit: src.recordsUnit || "rows",
    ragStatus: normalizeRagStatus(src.ragStatus),
    ragIndexed: ragCount,
    namespace: src.namespace || sourceNamespaceMap[id] || null,
    sheetName: src.sheetName || null,
  };
}

const sources = sourceOrder
  .filter(id => normalizedById[id])
  .map(id => normalizedById[id]);

const activeSources = sources.filter(s => s.status === "Synced").length;
const ragIndexed = sources.reduce((sum, s) => sum + (Number(s.ragIndexed) || 0), 0);
const recordsProcessed = sources.reduce((sum, s) => sum + (Number(s.recordsPulled) || 0), 0);

const lastGlobalSyncTimeRaw =
  sources
    .map(s => s.lastSyncTimeRaw)
    .filter(Boolean)
    .sort()
    .slice(-1)[0] || new Date().toISOString();

return [
  {
    json: {
      summaryCards: {
        activeSources,
        ragIndexed,
        recordsProcessed,
      },
      activeSources,
      ragIndexed,
      recordsProcessed,
      lastGlobalSyncTime: formatDisplayTime(lastGlobalSyncTimeRaw),
      lastGlobalSyncTimeRaw,
      sources,
    },
  },
];

