const cfg = $item(0).$node["Config Ingest"].json;

return [

  {
    json: {
      lane: 'returns',
      namespace: 'RAG1',
      natural_query: cfg.returns_query || 'product received damaged defective wrong item size mismatch description inaccurate manufacturing defect premature failure unusable on arrival',
      top_k: 40
