  .filter((item) => {
    const meta = item.json.document?.metadata || {};

    const key = [
      meta.lane || '',
      meta.namespace || '',
      meta.row_number || ''
    ].join('|');

    if (seen.has(key)) return false;

    seen.add(key);
    return true;
  })
  .map((item, idx) => {
    const doc = item.json.document || {};
    const text =
      doc.pageContent ||
      item.json.pageContent ||
      item.json.text ||
      '';

    return text ? `[${idx + 1}] ${text}` : '';
  })
  .filter(Boolean);

return [{
  json: {
    lane: 'returns',
    namespace: 'RAG1',
    natural_query: $item(0).$node["Config Ingest"].json["returns_query"],
    evidence_count: chunks.length,
    retrieved_context: chunks.join('\n\n')
  }
}];

