    if (!text) return '';

    return `[${idx + 1}]
Customer Feedback Context:
${text}`;
  })
  .filter(Boolean);

return [{
  json: {
    lane: 'nps',
    namespace: 'RAG5',
    natural_query: $item(0).$node["Config Ingest"].json["nps_query"],
    evidence_count: chunks.length,
    retrieved_context: chunks.join('\n\n')
  }
}];

const raw = items[0]?.json || {};
let candidate = raw.text || raw.response || raw.output || raw.message || raw.content || '';

if (typeof candidate !== 'string') {
  candidate = JSON.stringify(candidate || {});
}

let cleaned = candidate.trim();

if (cleaned.startsWith('```json')) {
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
} else if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
}

let parsed = null;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = null;
}

const obj = parsed && typeof parsed === 'object' ? parsed : {};

const normArr = (v) => {
  if (!v) return [];
  if (Array.isArray(v)) {
    return v
      .map((x) => {
        if (typeof x === 'string') return x.trim();
        if (x && typeof x === 'object') return JSON.stringify(x);
        return String(x ?? '').trim();
      })
      .filter(Boolean);
  }
  if (typeof v === 'string') {
    return v
      .split(/\s*\|\s*|\n|;;|;/)
      .map((s) => s.trim())
      .filter(Boolean);
  }
  return [String(v)];
};

const isLikelyPlaceholderNote = (notes) => {
  if (!notes || typeof notes !== 'string') return false;
  const n = notes.toLowerCase();
  return (
    (n.includes('"natural_query"') || n.includes('natural_query')) &&
    (n.includes('"top_k"') || n.includes('top_k'))
  );
};

const normalizePriorityIssue = (issue) => {
  if (!issue) return null;

  if (typeof issue === 'string') {
    return {
      title: issue,
      confidence_score: null,
      grounded_score: null,
      event_count: null,
      supporting_lanes: [],
      driving_themes: []
    };
  }

  if (typeof issue === 'object') {
    return {
      title: String(issue.title || issue.problem || issue.issue || '').trim(),
      confidence_score:
        issue.confidence_score ?? issue.confidence ?? issue.score ?? null,
      grounded_score:
        issue.grounded_score ?? issue.groundedness_score ?? issue.grounded ?? null,
      event_count:
        Number(issue.event_count ?? issue.events ?? issue.evidence_count ?? 0) || 0,
      supporting_lanes: normArr(issue.supporting_lanes || issue.sources || issue.lanes),
      driving_themes: normArr(issue.driving_themes || issue.drivers || issue.themes).slice(0, 4)
    };
  }

  return null;
};

const priorityIssuesRaw = Array.isArray(obj.priority_issues)
  ? obj.priority_issues
  : normArr(obj.priority_issues);

const priority_issues_array = priorityIssuesRaw
  .map(normalizePriorityIssue)
  .filter((x) => x && x.title);

const cross_lane_patterns_array = Array.isArray(obj.cross_lane_patterns)
  ? obj.cross_lane_patterns.map((x) => String(x))
  : normArr(obj.cross_lane_patterns);

const recommended_actions_array = Array.isArray(obj.recommended_actions)
  ? obj.recommended_actions.map((x) => String(x))
  : normArr(obj.recommended_actions);

const follow_up_questions_array = Array.isArray(obj.follow_up_questions)
  ? obj.follow_up_questions.map((x) => String(x)).slice(0, 4)
  : normArr(obj.follow_up_questions).slice(0, 4);

const rawLaneSummaries = Array.isArray(obj.lane_summaries) ? obj.lane_summaries : [];

const normalizedLaneSummaries = rawLaneSummaries.map((x) => {
  const themes = normArr(x.top_themes || x.themes);
  const examples = normArr(x.evidence_examples);
  const notes = x.notes || '';
  const evidence_count = Number(x.evidence_count ?? x.evidencecount ?? 0) || 0;

  return {
    lane: String(x.lane || '').trim(),
    namespace: String(x.namespace || '').trim(),
    evidence_count,
    top_themes: themes,
    notes,
    evidence_examples: examples
  };
});

const grouped = new Map();

for (const ls of normalizedLaneSummaries) {
  const key = `${String(ls.lane || '').toLowerCase()}|${String(ls.namespace || '').toLowerCase()}`;
  const existing = grouped.get(key);

  if (!existing) {
    grouped.set(key, { ...ls });
    continue;
  }

  const existingScore =
    (existing.evidence_count * 100) +
    (existing.top_themes.length * 10) +
    (existing.evidence_examples.length * 5) +
    (isLikelyPlaceholderNote(existing.notes) ? -25 : 0);

  const incomingScore =
    (ls.evidence_count * 100) +
    (ls.top_themes.length * 10) +
    (ls.evidence_examples.length * 5) +
    (isLikelyPlaceholderNote(ls.notes) ? -25 : 0);

  const best = incomingScore > existingScore ? ls : existing;
  const other = incomingScore > existingScore ? existing : ls;

  grouped.set(key, {
    lane: best.lane || other.lane,
    namespace: best.namespace || other.namespace,
    evidence_count: Math.max(best.evidence_count || 0, other.evidence_count || 0),
    top_themes: [...new Set([...(best.top_themes || []), ...(other.top_themes || [])])].slice(0, 8),
    evidence_examples: [...new Set([...(best.evidence_examples || []), ...(other.evidence_examples || [])])].slice(0, 5),
    notes:
      !isLikelyPlaceholderNote(best.notes) && best.notes
        ? best.notes
        : other.notes || best.notes || ''
  });
}

const dedupedLaneSummaries = Array.from(grouped.values());

const byLane = Object.fromEntries(
  dedupedLaneSummaries.map((x) => [String(x.lane || '').toLowerCase(), x])
);

const formatLaneSummary = (x) => {
  if (!x) return { compact: '', structured: null };

  const themes = normArr(x.top_themes || x.themes);
  const notes = x.notes || '';
  const examples = normArr(x.evidence_examples);
  const evidence_count = Number(x.evidence_count ?? x.evidencecount ?? 0) || 0;

  const compact = `Themes: ${themes.join('; ')}${
    examples.length ? ' | Evidence examples: ' + examples.join(' | ') : ''
  } | Notes: ${notes}`;

  const structured = {
    lane: x.lane || '',
    namespace: x.namespace || '',
    evidence_count,
    top_themes: themes,
    notes,
    evidence_examples: examples
  };

  return { compact, structured };
};

const returnsFmt = formatLaneSummary(byLane.returns);
const crmFmt = formatLaneSummary(byLane.crm);
const reviewsFmt = formatLaneSummary(byLane.reviews);
const fraudFmt = formatLaneSummary(byLane.fraud);
const npsFmt = formatLaneSummary(byLane.nps);

const totalEvents =
  dedupedLaneSummaries.reduce(
    (s, l) => s + (Number(l.evidence_count ?? l.evidencecount ?? 0) || 0),
    0
  ) || 0;

const priority_issues_text = priority_issues_array
  .map((x) => x.title)
  .filter(Boolean)
  .join(' | ');

const cross_lane_patterns_text = cross_lane_patterns_array.join(' | ');
const recommended_actions_text = recommended_actions_array.join(' | ');
const follow_up_questions_text = follow_up_questions_array.join(' | ');

return [
  {
    json: {
      run_timestamp: new Date().toISOString(),
      report_title: obj.report_title || 'Customer Experience Master Summary',
      overall_summary: obj.overall_summary || cleaned || 'No master summary returned.',

      priority_issues: priority_issues_array,
      cross_lane_patterns: cross_lane_patterns_array,
      recommended_actions: recommended_actions_array,
      follow_up_questions: follow_up_questions_array,

      priority_issues_text,
      cross_lane_patterns_text,
      recommended_actions_text,
      follow_up_questions_text,

      lane_output_count: dedupedLaneSummaries.length,
      total_events_analyzed: totalEvents,

      returns_summary: returnsFmt.compact,
      crm_summary: crmFmt.compact,
      reviews_summary: reviewsFmt.compact,
      fraud_summary: fraudFmt.compact,
      nps_summary: npsFmt.compact,

      lane_summaries: [
        returnsFmt.structured,
        crmFmt.structured,
        reviewsFmt.structured,
        fraudFmt.structured,
        npsFmt.structured
      ].filter(Boolean),

      static_questions: {
        question_1: follow_up_questions_array[0] || '',
        question_2: follow_up_questions_array[1] || '',
        question_3: follow_up_questions_array[2] || '',
        question_4: follow_up_questions_array[3] || ''
      },

      raw_master_json_obj: obj,
      raw_master_text: cleaned
    }
  }
];

const normalized = items.map((item, idx) => {
  const raw = item.json || {};
  let candidate = raw.text || raw.response || raw.output || raw.message || raw.content || '';

  if (typeof candidate !== 'string') {
    candidate = JSON.stringify(candidate || {});
  }

  let cleaned = candidate.trim();

  if (cleaned.startsWith('```json')) {
    cleaned = cleaned.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
  } else if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  }

  let parsed = null;
  if (cleaned) {
    try {
      parsed = JSON.parse(cleaned);
    } catch (e) {}
  }

  const obj = parsed && typeof parsed === 'object' ? parsed : raw;

  const lane = obj.lane || raw.lane || `lane_${idx + 1}`;
  const namespace = obj.namespace || raw.namespace || '';
  const evidence_count = Number(
    obj.evidence_count ?? obj.evidencecount ?? raw.evidence_count ?? raw.evidencecount ?? 0
  );

  let themes = obj.themes ?? raw.themes ?? [];
  if (Array.isArray(themes)) {
    themes = themes
      .map((t) => {
        if (typeof t === 'string') return t;
        if (t && typeof t === 'object') {
          const theme = t.theme || '';
          const description = t.description || '';
          return [theme, description].filter(Boolean).join(': ');
        }
        return String(t ?? '');
      })
      .filter(Boolean);
  } else if (themes && typeof themes === 'object') {
    themes = [JSON.stringify(themes)];
  } else if (typeof themes === 'string') {
    themes = themes.split(';').map((s) => s.trim()).filter(Boolean);
  } else {
    themes = [];
  }

  let evidence_examples = obj.evidence_examples ?? raw.evidence_examples ?? [];

  if (Array.isArray(evidence_examples)) {
    evidence_examples = evidence_examples
      .map((e) => {
        if (typeof e === 'string') return e;
        if (typeof e === 'object') return JSON.stringify(e);
        return String(e ?? '');
      })
      .filter(Boolean);
  } else if (typeof evidence_examples === 'string') {
    evidence_examples = [evidence_examples];
  } else {
    evidence_examples = [];
  }

  const notes = (obj.notes ?? raw.notes ?? cleaned) || JSON.stringify(raw);

  return {
    lane,
    namespace,
    evidence_count,
    themes,
    notes,
    evidence_examples
  };
});

const masterContext = normalized.length
  ? normalized
      .map((x, idx) =>
        [
          `[${idx + 1}] Lane: ${x.lane}`,
          `Namespace: ${x.namespace}`,
          `Evidence count: ${x.evidence_count}`,
          `Themes: ${Array.isArray(x.themes) ? x.themes.join('; ') : x.themes}`,
          `Evidence examples: ${
            x.evidence_examples.length ? x.evidence_examples.join(' | ') : 'None'
          }`,
          `Notes: ${typeof x.notes === 'string' ? x.notes : JSON.stringify(x.notes)}`
        ].join('\n')
      )
      .join('\n\n')
  : 'No lane outputs with evidence were found.';

return [
  {
    json: {
      lane_output_count: normalized.length,
      master_context: masterContext,
      lane_outputs: normalized,
      lane_outputs_json: JSON.stringify(normalized)
    }
  }
];

