const seen = new Set();

const chunks = items
  .filter((item) => {
    const meta = item.json.document?.metadata || {};
    const key = `${meta.lane}|${meta.namespace}|${meta.row_number}`;

    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .map((item, idx) => {
    const doc = item.json.document || {};
    const meta = doc.metadata || {};
    const text = doc.pageContent || item.json.pageContent || item.json.text || '';

    if (!text) return '';

    return `[${idx + 1}]
Fraud Investigation Context:
${text}`;
  })
  .filter(Boolean);

return [{
  json: {
    lane: 'fraud',
    namespace: 'RAG4',
    natural_query: $item(0).$node["Config Ingest"].json["fraud_query"],
    evidence_count: chunks.length,
    retrieved_context: chunks.join('\n\n')
  }
}];

const master = $json || {};

// Prefer parsed master object if available
let raw = {};
if (master.raw_master_json_obj && typeof master.raw_master_json_obj === 'object') {
  raw = master.raw_master_json_obj;
} else if (master.raw_master_json) {
  try {
    raw = typeof master.raw_master_json === 'string'
      ? JSON.parse(master.raw_master_json)
      : master.raw_master_json;
  } catch (e) {
    raw = master.raw_master_json || {};
  }
}

// Helpers
const safeArr = (v) => {
  if (!v) return [];
  if (Array.isArray(v)) {
    return v
      .map((x) => {
        if (x == null) return '';
        if (typeof x === 'string') return x.trim();
        return String(x).trim();
      })
      .filter(Boolean);
  }
  if (typeof v === 'string') {
    return v.split(/\s*\|\s*|\n/).map(s => s.trim()).filter(Boolean);
  }
  return [String(v).trim()].filter(Boolean);
};

const unique = (arr) => [...new Set((arr || []).filter(Boolean))];

const normalizePriorityIssue = (issue) => {
  if (!issue) return null;

  if (typeof issue === 'string') {
    return {
      title: issue.trim(),
      confidence_score: null,
      grounded_score: null,
      event_count: null,
      supporting_lanes: [],
      driving_themes: []
    };
  }

  if (typeof issue === 'object') {
    return {
      title: String(issue.title || issue.problem || issue.issue || '').trim(),
      confidence_score:
        issue.confidence_score != null ? Number(issue.confidence_score) :
        issue.confidence != null ? Number(issue.confidence) :
        null,
      grounded_score:
        issue.grounded_score != null ? Number(issue.grounded_score) :
        issue.grounded != null ? Number(issue.grounded) :
        null,
      event_count:
        issue.event_count != null ? Number(issue.event_count) :
        issue.events != null ? Number(issue.events) :
        issue.evidence_count != null ? Number(issue.evidence_count) :
        null,
      supporting_lanes: safeArr(issue.supporting_lanes || issue.sources || issue.lanes),
      driving_themes: safeArr(issue.driving_themes || issue.drivers || issue.themes).slice(0, 4)
    };
  }

  return null;
};

// lane summaries: prefer structured top-level, then raw
const laneSummaries = Array.isArray(master.lane_summaries) && master.lane_summaries.length
  ? master.lane_summaries
  : Array.isArray(raw.lane_summaries)
    ? raw.lane_summaries
    : [];

// normalize lane summaries
const normalizedLaneSummaries = laneSummaries.map(ls => ({
  lane: String(ls.lane || ls.laneName || '').trim(),
  namespace: String(ls.namespace || '').trim(),
  evidence_count: Number(ls.evidence_count ?? ls.evidencecount ?? 0) || 0,
  top_themes: Array.isArray(ls.top_themes)
    ? ls.top_themes.map(String).filter(Boolean)
    : (Array.isArray(ls.themes) ? ls.themes.map(String).filter(Boolean) : safeArr(ls.top_themes || ls.themes)),
  notes: String(ls.notes || ''),
  evidence_examples: Array.isArray(ls.evidence_examples)
    ? ls.evidence_examples.map(String).filter(Boolean)
    : safeArr(ls.evidence_examples || [])
}));

const totalEvents = Number(
  master.total_events_analyzed ??
  master.total_events ??
  normalizedLaneSummaries.reduce((s, l) => s + (Number(l.evidence_count) || 0), 0)
) || 0;

// priorities: normalize to object form
let prioritiesRaw = Array.isArray(raw.priority_issues) && raw.priority_issues.length
  ? raw.priority_issues.slice()
  : Array.isArray(master.priority_issues) && master.priority_issues.length
    ? master.priority_issues.slice()
    : [];

if (!prioritiesRaw.length) {
  const themeCounts = {};
  normalizedLaneSummaries.forEach(ls => {
    (ls.top_themes || []).forEach(t => {
      themeCounts[t] = (themeCounts[t] || 0) + (ls.evidence_count || 1);
    });
  });

  prioritiesRaw = Object.entries(themeCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(x => ({
      title: x[0],
      confidence_score: null,
      grounded_score: null,
      event_count: x[1],
      supporting_lanes: [],
      driving_themes: [x[0]]
    }));
}

let priorities = prioritiesRaw
  .map(normalizePriorityIssue)
  .filter(p => p && p.title);

const seenTitles = new Set();
priorities = priorities.filter(p => {
  const key = p.title.toLowerCase().trim();
  if (!key || seenTitles.has(key)) return false;
  seenTitles.add(key);
  return true;
}).slice(0, 5);

// follow-up questions
let followUpQuestions = Array.isArray(master.follow_up_questions) && master.follow_up_questions.length
  ? master.follow_up_questions.slice(0, 4).map(String)
  : Array.isArray(raw.follow_up_questions) && raw.follow_up_questions.length
    ? raw.follow_up_questions.slice(0, 4).map(String)
    : [];

let staticQuestions = master.static_questions && typeof master.static_questions === 'object'
  ? master.static_questions
  : raw.static_questions && typeof raw.static_questions === 'object'
    ? raw.static_questions
    : null;

if (!staticQuestions) {
  staticQuestions = {
    question_1: followUpQuestions[0] || '',
    question_2: followUpQuestions[1] || '',
    question_3: followUpQuestions[2] || '',
    question_4: followUpQuestions[3] || ''
  };
}

if (!followUpQuestions.length) {
  followUpQuestions = [
    staticQuestions.question_1 || '',
    staticQuestions.question_2 || '',
    staticQuestions.question_3 || '',
    staticQuestions.question_4 || ''
  ].filter(Boolean).slice(0, 4);
}

function aggregateForPriority(priorityObj) {
  const pTitle = String(priorityObj.title || '').toLowerCase();
  const driversSet = new Set(safeArr(priorityObj.driving_themes));
  const sourcesSet = new Set(safeArr(priorityObj.supporting_lanes));
  let supportingCount = Number(priorityObj.event_count || 0) || 0;
  const evidenceSamples = [];

  normalizedLaneSummaries.forEach(ls => {
    const laneName = String(ls.lane || '').toLowerCase();
    const laneIsExplicitSupport = safeArr(priorityObj.supporting_lanes).map(x => x.toLowerCase()).includes(laneName);

    const themeMatches = (ls.top_themes || []).filter(t => {
      const tl = String(t || '').toLowerCase();
      if (!tl || !pTitle) return false;
      return (
        tl.includes(pTitle) ||
        pTitle.includes(tl) ||
        tl.split(' ').some(w => w && pTitle.includes(w))
      );
    });

    if (laneIsExplicitSupport || themeMatches.length > 0) {
      if (!safeArr(priorityObj.supporting_lanes).length) {
        sourcesSet.add(ls.lane || '');
      }

      if (!(Number(priorityObj.event_count || 0) > 0)) {
        supportingCount += (ls.evidence_count || 0);
      }

      themeMatches.forEach(m => driversSet.add(m));

      if (ls.evidence_examples && ls.evidence_examples.length) {
        ls.evidence_examples.slice(0, 3).forEach(sn => {
          evidenceSamples.push({
            lane: ls.lane,
            namespace: ls.namespace,
            snippet: String(sn).slice(0, 120)
          });
        });
      } else if (ls.notes && !ls.notes.includes('"natural_query"')) {
        evidenceSamples.push({
          lane: ls.lane,
          namespace: ls.namespace,
          snippet: String(ls.notes).slice(0, 120)
        });
      }
    }
  });

  return {
    drivers: Array.from(driversSet).filter(Boolean).slice(0, 4),
    sources: Array.from(sourcesSet).filter(Boolean),
    supportingCount,
    evidenceSamples: evidenceSamples.slice(0, 5)
  };
}

// build insights
let insights = priorities.map((p, i) => {
  const agg = aggregateForPriority(p);

  const events =
    p.event_count != null && !Number.isNaN(Number(p.event_count))
      ? Number(p.event_count)
      : (agg.supportingCount || (totalEvents > 0 ? Math.max(1, Math.round(totalEvents / Math.max(1, priorities.length))) : 0));

  let summary = '';
  const combinedSummary = master.overall_summary || raw.overall_summary || '';
  if (combinedSummary && typeof combinedSummary === 'string') {
    const idx = combinedSummary.toLowerCase().indexOf(p.title.toLowerCase());
    if (idx >= 0) {
      const start = Math.max(0, idx - 60);
      summary = combinedSummary.slice(start, Math.min(combinedSummary.length, idx + 180)).trim();
    }
  }

  if (!summary) {
    const driversText = agg.drivers.length ? agg.drivers.slice(0, 2).join(', ') : 'related issues';
    summary = `${p.title} appearing across ${agg.sources.length || 1} source(s); drivers: ${driversText}.`;
  }

  const confidence =
    p.confidence_score != null
      ? Number(p.confidence_score)
      : Number((master.confidence ?? 0.85));

  const grounded =
    p.grounded_score != null
      ? Number(p.grounded_score)
      : Number((master.grounded_score ?? 0.9));

  return {
    rank: i + 1,
    title: p.title,
    confidence,
    grounded_score: grounded,
    events,
    sources: agg.sources,
    drivers: agg.drivers,
    evidence_sample: agg.evidenceSamples,
    summary
  };
});

// post-processing
const total = Number(totalEvents || 0);

insights.forEach(ins => {
  if (total > 0 && ins.events > total) {
    ins.events = Math.min(ins.events, total);
    ins.note_overlap = 'events may overlap with other insights; counts capped to total_events_analyzed';
  }

  if (!(ins.grounded_score > 0)) {
    const support = ins.events || 0;
    ins.grounded_score = Number(Math.min(0.99, (support / Math.max(1, total)) + 0.15).toFixed(2));
  }

  if (!(ins.confidence > 0)) {
    const laneCount = (ins.sources && ins.sources.length) ? ins.sources.length : 0;
    const evidenceBonus = (ins.evidence_sample && ins.evidence_sample.length > 1) ? 0.05 : 0;
    ins.confidence = Number(Math.min(0.98, 0.6 + (0.08 * laneCount) + evidenceBonus).toFixed(2));
  }
});

const merged = [];
const seen = [];

insights.forEach(ins => {
  const norm = String(ins.title || '').toLowerCase().replace(/[^a-z0-9 ]/g, '').trim();

  const foundIndex = seen.findIndex(s => {
    const sWords = s.split(' ').filter(Boolean);
    const nWords = norm.split(' ').filter(Boolean);
    const overlap = nWords.filter(w => sWords.includes(w)).length;
    return overlap / Math.max(nWords.length, 1) > 0.5 || s.includes(norm) || norm.includes(s);
  });

  if (foundIndex >= 0) {
    const ex = merged[foundIndex];
    ex.events = Math.min(total || (ex.events + ins.events), (ex.events || 0) + (ins.events || 0));
    ex.sources = Array.from(new Set([...(ex.sources || []), ...(ins.sources || [])]));
    ex.drivers = Array.from(new Set([...(ex.drivers || []), ...(ins.drivers || [])]));
    ex.evidence_sample = (ex.evidence_sample || []).concat(ins.evidence_sample || []).slice(0, 5);

    if (!String(ex.summary || '').includes(String(ins.summary || ''))) {
      ex.summary = `${ex.summary} ${ins.summary}`.trim().slice(0, 300);
    }

    ex.confidence = Number(Math.min(0.98, ((Number(ex.confidence || 0) + Number(ins.confidence || 0)) / 2)).toFixed(2));
    ex.grounded_score = Number(Math.min(0.99, ((Number(ex.grounded_score || 0) + Number(ins.grounded_score || 0)) / 2)).toFixed(2));
  } else {
    seen.push(norm);
    merged.push(JSON.parse(JSON.stringify(ins)));
  }
});

merged.sort((a, b) => (b.events || 0) - (a.events || 0));
merged.forEach((m, i) => m.rank = i + 1);

const finalInsights = merged.slice(0, 5);

const payload = {
  job_id: master.request_id || master.job_id || `signal-${Date.now()}`,
  status: 'completed',
  generated_at: new Date().toISOString(),
  time_range: master.time_window || '7d',
  total_events_analyzed: totalEvents,
  signals_used: unique(normalizedLaneSummaries.map(l => l.lane)).filter(Boolean),
  insights: finalInsights,
  lane_summaries: normalizedLaneSummaries,
  follow_up_questions: followUpQuestions,
  static_questions: staticQuestions,
  raw_master_json: raw
};

return [{ json: payload }];

