  cleaned = cleaned.replace(/^```json/i, '').replace(/```$/i, '').trim();
} else if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```/i, '').replace(/```$/i, '').trim();
}

let parsed = null;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = null;
}

const lowerQuery = query.toLowerCase();

const wantsSingleParagraph =
  /one paragraph|single paragraph|in a paragraph|single para|one para/.test(lowerQuery);

const wantsBulletsOnly =
  /bullet points only|bullets only|only bullets|bullet points|bullets\b/.test(lowerQuery) &&
  !/numbered|numbers|number list|ordered list/.test(lowerQuery);

const wantsTable =
  /table|tabular|in a table|as a table/.test(lowerQuery);

function formatReply(text) {
  let t = String(text || '').trim();
  t = t.replace(/\r\n/g, '\n').trim();

  if (!t) return t;

  if (wantsTable) {
    return t.replace(/\n{3,}/g, '\n\n').trim();
  }

  if (wantsSingleParagraph) {
    return t.replace(/\n+/g, ' ').replace(/[ \t]+/g, ' ').trim();
  }

  if (wantsBulletsOnly) {
    t = t.replace(/[ \t]+/g, ' ');
    t = t.replace(
      /(Here are the main customer problems across the available sources:|The main customer problems are:)/gi,
      ''
    );
    t = t.replace(/\s+(\d+\.\s)/g, '\n$1');
    t = t.replace(/^\d+\.\s+/gm, '- ');
    t = t.replace(/\n\d+\.\s+/g, '\n- ');
    t = t.replace(/\s+(Seen in:\s*[^\n]+)/gi, '\n  $1');
    t = t.replace(/\s+(What this suggests:)/gi, '\n\n$1');
    t = t.replace(/\s+(Evidence gaps:)/gi, '\n\n$1');
    t = t.replace(/\s+-\s+/g, '\n- ');
    t = t.replace(/:\s+-/g, ':\n- ');
    t = t.replace(/\n{3,}/g, '\n\n');
    return t.trim();
  }

  t = t.replace(/[ \t]+/g, ' ');
  t = t.replace(
    /(Here are the main customer problems across the available sources:|The main customer problems are:)/gi,
    '$1\n\n'
  );
  t = t.replace(/\s+(\d+\.\s)/g, '\n\n$1');
  t = t.replace(/\s+(Seen in:\s*[^\n]+)/gi, '\n$1');
  t = t.replace(/\s+(What this suggests:)/gi, '\n\n$1');
  t = t.replace(/\s+(Evidence gaps:)/gi, '\n\n$1');
  t = t.replace(/\s+-\s+/g, '\n- ');
  t = t.replace(/:\s+-/g, ':\n- ');
  t = t.replace(/\n{3,}/g, '\n\n');

  return t.trim();
}

const rawReply = String(parsed?.reply ?? cleaned ?? 'I could not generate a reply.').trim();
const reply = formatReply(rawReply);

let issuesFound = getFirst(parsed?.issues_found, parsed?.issuesfound, []);
if (!Array.isArray(issuesFound)) issuesFound = [];

issuesFound = issuesFound
  .map((x) => {
    const issue = String(x?.issue ?? '').trim();
    const summary = String(x?.summary ?? x?.whyitmatters ?? x?.likelyrootcause ?? '').trim();

    let lanes = getFirst(x?.lanes, x?.evidencelanes, []);
    if (!Array.isArray(lanes)) lanes = [];
    lanes = [...new Set(lanes.map(v => String(v).trim()).filter(Boolean))];

    if (!issue && !summary) return null;
    return { issue, summary, lanes };
  })
  .filter(Boolean)
  .slice(0, 5);

let lanesUsed = getFirst(parsed?.lanes_used, parsed?.lanesused, sourceLanes, []);
if (!Array.isArray(lanesUsed)) lanesUsed = [];
lanesUsed = [...new Set(lanesUsed.map(v => String(v).trim()).filter(Boolean))];

const updatedHistory = [
  ...history,
  { user: query, assistant: reply }
].slice(-5);

if (sessionId) {
  store.chat_sessions[sessionId] = updatedHistory;
}

return [{
  json: {
    sessionid: sessionId,
    query,
    reply,
    issues_found: issuesFound,
    lanes_used: lanesUsed,
    history: updatedHistory,
    meta: {
      topk: topK,
      retrievedcount: retrievedCount,
      answer_mode: answerMode
    }
  }
}];
